1	'use client';
2	
3	import {
4	    Button,
5	    Divider,
6	    Paper,
7	    Table,
8	    TableTbody,
9	    TableTd,
10	    TableTh,
11	    TableThead,
12	    TableTr,
13	    Title,
14	    type TitleOrder,
15	    VisuallyHidden,
16	} from '@mantine/core';
17	import { useDisclosure } from '@mantine/hooks';
18	import { IconChevronDown, IconChevronUp } from '@tabler/icons-react';
19	import { type TableName, TableNameSchema } from 'prisma/zod/schemas';
20	import { useId, useMemo } from 'react';
21	
22	import { PlayerLink } from '@/components/PlayerLink/PlayerLink';
23	import { TableScore } from '@/components/TableScore/TableScore';
24	import { config } from '@/lib/config';
25	import { PlayerRecordDataType } from '@/types';
26	
27	export interface Props {
28	    table: TableName;
29	    year: number;
30	    records: PlayerRecordDataType[];
31	    title?: string;
32	    titleOrder?: TitleOrder;
33	}
34	
35	const rankFieldByTable = {
36	    [TableNameSchema.enum.points]: 'rankPoints',
37	    [TableNameSchema.enum.averages]: 'rankAverages',
38	    [TableNameSchema.enum.stalwart]: 'rankStalwart',
39	    [TableNameSchema.enum.speedy]: 'rankSpeedy',
40	    [TableNameSchema.enum.pub]: 'rankPub',
41	} satisfies Record<TableName, keyof PlayerRecordDataType>;
42	
43	type RankField = (typeof rankFieldByTable)[TableName];
44	
45	const scoreHeadingByTable = {
46	    [TableNameSchema.enum.points]: 'Points',
47	    [TableNameSchema.enum.averages]: 'Average',
48	    [TableNameSchema.enum.stalwart]: 'Games Played',
49	    [TableNameSchema.enum.speedy]: 'Average Response Time (hh:mm:ss)',
50	    [TableNameSchema.enum.pub]: 'Pub Score',
51	} satisfies Record<TableName, string>;
52	
53	interface RankDisplay {
54	    text: string;
55	    visible: boolean;
56	}
57	
58	const rankDisplays = (records: PlayerRecordDataType[], rankField: RankField): RankDisplay[] => {
59	    const displays: RankDisplay[] = [];
60	    let prevRank: number | null | undefined;
61	
62	    for (const record of records) {
63	        const rank = record[rankField];
64	        const isMissing = rank === null || rank === undefined;
65	
66	        displays.push({
67	            text: isMissing ? '-' : `${rank}`,
68	            visible: isMissing || rank !== prevRank,
69	        });
70	
71	        prevRank = rank;
72	    }
73	
74	    return displays;
75	};
76	
77	// Extends the initial page of rows forward past any tie straddling the cutoff,
78	// so a group of equally-ranked players is never split across the toggle.
79	const visibleRowCount = (ranks: RankDisplay[], initial: number): number => {
80	    let count = Math.min(initial, ranks.length);
81	
82	    while (count < ranks.length && !ranks[count].visible) {
83	        count++;
84	    }
85	
86	    return count;
87	};
88	
89	export const RecordsTable = ({ table, year, records, title, titleOrder = 2 }: Props) => {
90	    const rankField = rankFieldByTable[table];
91	    const scoreHeading = scoreHeadingByTable[table];
92	    const ranks = useMemo(() => rankDisplays(records, rankField), [records, rankField]);
93	    const cutoff = useMemo(
94	        () => visibleRowCount(ranks, config.recordsTableVisibleRows),
95	        [ranks],
96	    );
97	    const [opened, { toggle }] = useDisclosure(false);
98	    const hiddenCount = records.length - cutoff;
99	    const visibleRecords = opened ? records : records.slice(0, cutoff);
100	    const tbodyId = useId();
101	
102	    return (
103	        <Paper p="sm" miw="14rem" maw="24rem" withBorder>
104	            {title ? (
105	                <>
106	                    <Title order={titleOrder} mb="xs" w="100%" ta="center">{title}</Title>
107	                    <Divider mb="xs" />
108	                </>
109	            ) : null}
110	            <Table stickyHeader stickyHeaderOffset={0}>
111	                <TableThead>
112	                    <TableTr bd="0">
113	                        <TableTh p={0}><VisuallyHidden>Position</VisuallyHidden></TableTh>
114	                        <TableTh p={0}><VisuallyHidden>Player</VisuallyHidden></TableTh>
115	                        <TableTh p={0}><VisuallyHidden>{scoreHeading}</VisuallyHidden></TableTh>
116	                    </TableTr>
117	                </TableThead>
118	                <TableTbody id={tbodyId}>
119	                    {visibleRecords.map((record, index) => (
120	                        <TableTr
121	                            key={record.id}
122	                            bd={ranks[index + 1]?.visible === false ? '0' : undefined}
123	                        >
124	                            <TableTd>
125	                                {ranks[index].visible ?
126	                                    ranks[index].text :
127	                                    <VisuallyHidden>{ranks[index].text}</VisuallyHidden>}
128	                            </TableTd>
129	                            <TableTd>
130	                                <PlayerLink player={record.player} year={year} />
131	                            </TableTd>
132	                            <TableTd>
133	                                <TableScore table={table} playerRecord={record} />
134	                            </TableTd>
135	                        </TableTr>
136	                    ))}
137	                </TableTbody>
138	            </Table>
139	            {hiddenCount > 0 &&
140	                <Button
141	                    onClick={toggle}
142	                    variant="subtle"
143	                    fullWidth
144	                    mt="xs"
145	                    aria-expanded={opened}
146	                    aria-controls={tbodyId}
147	                    rightSection={opened ? <IconChevronUp size={16} /> : <IconChevronDown size={16} />}
148	                >
149	                    {opened ? 'Show less' : `Show ${hiddenCount} more`}
150	                </Button>
151	            }
152	        </Paper>
153	    );
154	};
