21	export const WinnersTable = ({ table, records }: Props) => {
22	    const rows = records.map((winner, index) => {
23	        const year = index > 0 && records[index - 1].year === winner.year ? '' : winner.year;
24	        return (
25	            <TableTr key={index}>
26	                <TableTd>{year}</TableTd>
27	                <TableTd><PlayerLink player={winner.player} year={winner.year} /></TableTd>
28	            </TableTr>
29	        );
30	    });
31	
32	    return rows.length > 0 ? (
33	        <Paper p="lg" w="16em">
34	            <Title order={3}>{table.charAt(0).toUpperCase() + table.slice(1)}</Title>
35	
36	            <Table>
37	                <TableThead>
38	                    <TableTr>
39	                        <TableTh w="4em">Year</TableTh>
40	                        <TableTh w="auto">Winner(s)</TableTh>
41	                    </TableTr>
42	                </TableThead>
43	                <TableTbody>
44	                    {rows}
45	                </TableTbody>
46	            </Table>
47	        </Paper>
48	    ) : null;
49	};
