1	'use client';
2	
3	import {
4	    Button,
5	    Paper,
6	    Table,
7	    TableTbody,
8	    TableTd,
9	    TableTh,
10	    TableThead,
11	    TableTr,
12	} from '@mantine/core';
13	import { useDisclosure } from '@mantine/hooks';
14	import { IconChevronDown, IconChevronUp } from '@tabler/icons-react';
15	import { useId } from 'react';
16	
