21	
22	export interface Props {
23	    turnout: TurnoutByYearType[],
24	}
25	
26	export const Turnout = ({ turnout }: Props) => {
27	    const sortedTurnout = [...turnout].sort((a, b) => b.year - a.year);
28	    const [opened, { toggle }] = useDisclosure(false);
29	    const hiddenCount = Math.max(0, sortedTurnout.length - config.turnoutTableVisibleRows);
30	    const visibleTurnout = opened ?
31	        sortedTurnout :
32	        sortedTurnout.slice(0, config.turnoutTableVisibleRows);
33	    const tbodyId = useId();
34	
35	    const rows = visibleTurnout.map((t) => (
36	        <TableTr key={t.year}>
37	            <TableTd>{t.year}</TableTd>
38	            <TableTd>{t.gamesPlayed}</TableTd>
39	            <TableTd>{t.gamesCancelled}</TableTd>
40	            <TableTd>{t.responsesPerGameInitiated.toFixed(1)}</TableTd>
41	            <TableTd>{t.yessesPerGameInitiated.toFixed(1)}</TableTd>
42	            <TableTd>{t.playersPerGamePlayed.toFixed(1)}</TableTd>
43	        </TableTr>
44	    ));
45	
46	    return (
47	        <Paper p="sm" maw="24rem" withBorder>
48	            <Table stickyHeader stickyHeaderOffset={0} layout="fixed">
49	                <TableThead>
50	                    <TableTr>
51	                        <TableTh className={styles.verticalHeader}><span className={styles.verticalHeaderText}>Year</span></TableTh>
52	                        <TableTh className={styles.verticalHeader}><span className={styles.verticalHeaderText}>Played</span></TableTh>
53	                        <TableTh className={styles.verticalHeader}><span className={styles.verticalHeaderText}>Cancelled</span></TableTh>
54	                        <TableTh className={styles.verticalHeader}><span className={styles.verticalHeaderText}>Response Rate</span></TableTh>
55	                        <TableTh className={styles.verticalHeader}><span className={styles.verticalHeaderText}>Yes Rate</span></TableTh>
56	                        <TableTh className={styles.verticalHeader}><span className={styles.verticalHeaderText}>Turnout Rate</span></TableTh>
57	                    </TableTr>
58	                </TableThead>
59	                <TableTbody id={tbodyId}>{rows}</TableTbody>
60	            </Table>
61	            {hiddenCount > 0 &&
62	                <Button
63	                    onClick={toggle}
64	                    variant="subtle"
65	                    fullWidth
66	                    mt="xs"
67	                    aria-expanded={opened}
68	                    aria-controls={tbodyId}
69	                    rightSection={opened ? <IconChevronUp size={16} /> : <IconChevronDown size={16} />}
70	                >
71	                    {opened ? 'Show less' : `Show ${hiddenCount} more`}
72	                </Button>
73	            }
74	        </Paper>
75	    );
76	};
