1	import z from 'zod';
2	
3	/**
4	 * Zod schema and typed configuration for application settings.
5	 */
6	export interface ConfigType {
7	    /** Minimum games required to qualify for the averages table. */
8	    minGamesForAveragesTable: number;
9	    /** Minimum replies required to qualify for the speedy table. */
10	    minRepliesForSpeedyTable: number;
11	    /** Destination address for contact enquiries. */
12	    contactEmailDestination: string;
13	    /** Session revalidation interval in milliseconds. */
14	    sessionRevalidate: number;
15	    /** Notification auto close interval in milliseconds. */
16	    notificationAutoClose: number;
17	    /** Icon size for notifications. */
18	    notificationIconSize: number;
19	    /** Organiser's phone number for contact. */
20	    organiserPhoneNumber: string;
21	    /** Default game cost in pence. */
22	    defaultGameCostPence: number;
23	    /** Default hall cost in pence. */
24	    defaultHallCostPence: number;
25	    /** Maximum number of trophies to display individually in a player's trophy
26	     * section before resorting to a count. */
27	    trophyDisplayThreshold: number;
28	    /** Number of rows shown in a records table before the rest are hidden
29	     * behind a "show more" toggle. */
30	    recordsTableVisibleRows: number;
31	    /** Number of rows shown in the turnout-by-year table before older years
32	     * are hidden behind a "show more" toggle. */
33	    turnoutTableVisibleRows: number;
34	}
35	
36	export const ConfigSchema: z.ZodType<ConfigType> = z.object({
37	    minGamesForAveragesTable: z.number().int().nonnegative(),
38	    minRepliesForSpeedyTable: z.number().int().nonnegative(),
39	    contactEmailDestination: z.email(),
40	    sessionRevalidate: z.number().int().nonnegative(),
41	    notificationAutoClose: z.number().int().nonnegative(),
42	    notificationIconSize: z.number().int().nonnegative(),
43	    organiserPhoneNumber: z.string().min(1),
44	    defaultGameCostPence: z.number().int().min(1),
45	    defaultHallCostPence: z.number().int().min(1),
46	    trophyDisplayThreshold: z.number().int().min(1),
47	    recordsTableVisibleRows: z.number().int().min(1),
48	    turnoutTableVisibleRows: z.number().int().min(1),
49	});
