2	import { render, screen, within } from '@testing-library/react';
3	import userEvent from '@testing-library/user-event';
4	import { TableName, TableNameSchema } from 'prisma/zod/schemas';
5	import { vi } from 'vitest';
6	
7	import { Props as PlayerLinkProps } from '@/components/PlayerLink/PlayerLink';
8	import { RecordsTable } from '@/components/RecordsTable/RecordsTable';
9	import { Props as TableScoreProps } from '@/components/TableScore/TableScore';
10	import { config } from '@/lib/config';
11	import { extractMockProps, Wrapper } from '@/tests/components/lib/common';
12	import { createMockPlayerRecordData, defaultPlayerRecordDataList } from '@/tests/mocks/data/playerRecordData';
13	import { PlayerRecordDataType } from '@/types';
14	
15	vi.mock('@/components/PlayerLink/PlayerLink');
16	vi.mock('@/components/TableScore/TableScore');
17	
18	const getFirstDataRowCells = () => {
19	    const [, tbody] = screen.getAllByRole('rowgroup');
20	    const [firstRow] = within(tbody).getAllByRole('row');
21	    return within(firstRow).getAllByRole('cell');
22	};
23	
24	// Collapses JSX-formatting whitespace (newlines/indentation between
25	// expressions) so assertions compare against the meaningful text only.
26	const normalizeText = (text: string | null) => (text ?? '').replace(/\s+/g, ' ').trim();
27	
28	const getRankColumnValues = () => {
29	    const [, tbody] = screen.getAllByRole('rowgroup');
30	    const rows = within(tbody).getAllByRole('row');
31	    return rows.map((row) => normalizeText(within(row).getAllByRole('cell')[0].textContent));
32	};
33	
34	const getRankCell = (rowIndex: number) => {
35	    const [, tbody] = screen.getAllByRole('rowgroup');
36	    const rows = within(tbody).getAllByRole('row');
37	    return within(rows[rowIndex]).getAllByRole('cell')[0];
38	};
39	
40	// Text nodes sitting directly in the cell are what a sighted user sees;
41	// text inside a child element (the VisuallyHidden span) is accessible-only.
42	const getRankCellVisibleText = (cell: HTMLElement) =>
43	    normalizeText(
44	        Array.from(cell.childNodes)
45	            .filter((node) => node.nodeType === Node.TEXT_NODE)
46	            .map((node) => node.textContent)
47	            .join(''),
48	    );
49	
50	describe('RecordsTable', () => {
51	    it('renders qualified table with player records', () => {
52	        render(
53	            <Wrapper>
54	                <RecordsTable
55	                    table={TableNameSchema.enum.points}
56	                    year={2024}
57	                    records={defaultPlayerRecordDataList}
58	                />
59	            </Wrapper>,
60	        );
61	
62	        {
63	            const props = extractMockProps<PlayerLinkProps>('PlayerLink');
64	            expect(props.length).toBe(20);
65	            expect(props[0].player.name).toEqual("Gary Player");
66	        }
67	
68	        {
69	            const props = extractMockProps<TableScoreProps>('TableScore');
70	            expect(props.length).toBe(20);
71	            expect(props[0].table).toEqual(TableNameSchema.enum.points);
72	            expect(props[0].playerRecord.playerId).toEqual(12);
73	        }
74	    });
75	
76	    describe.each([
77	        [TableNameSchema.enum.points, 'rankPoints', 1, 'Points'],
78	        [TableNameSchema.enum.averages, 'rankAverages', 2, 'Average'],
79	        [TableNameSchema.enum.stalwart, 'rankStalwart', 3, 'Games Played'],
80	        [TableNameSchema.enum.speedy, 'rankSpeedy', 4, 'Average Response Time (hh:mm:ss)'],
81	        [TableNameSchema.enum.pub, 'rankPub', 5, 'Pub Score'],
82	    ] satisfies [TableName, keyof PlayerRecordDataType, number, string][])(
83	        'when table is "%s"',
84	        (table, rankField, expectedRank, expectedHeading) => {
85	            it(`renders the ${rankField} value in the rank column`, () => {
86	                render(
87	                    <Wrapper>
88	                        <RecordsTable
89	                            table={table}
90	                            year={2024}
91	                            records={[createMockPlayerRecordData({ [rankField]: expectedRank })]}
92	                        />
93	                    </Wrapper>,
94	                );
95	
96	                const [rankCell] = getFirstDataRowCells();
97	                expect(rankCell).toHaveTextContent(String(expectedRank));
98	            });
99	
100	            it(`renders '-' when ${rankField} is undefined`, () => {
101	                render(
102	                    <Wrapper>
103	                        <RecordsTable
104	                            table={table}
105	                            year={2024}
106	                            records={[createMockPlayerRecordData({ [rankField]: undefined })]}
107	                        />
108	                    </Wrapper>,
109	                );
110	
111	                const [rankCell] = getFirstDataRowCells();
112	                expect(rankCell).toHaveTextContent('-');
113	            });
114	
115	            it(`renders "${expectedHeading}" as the score column heading`, () => {
116	                render(
117	                    <Wrapper>
118	                        <RecordsTable
119	                            table={table}
120	                            year={2024}
121	                            records={[createMockPlayerRecordData()]}
122	                        />
123	                    </Wrapper>,
124	                );
125	
126	                const headings = screen.getAllByRole('columnheader');
127	                expect(headings).toHaveLength(3);
128	                expect(headings[2]).toHaveTextContent(expectedHeading);
129	            });
130	        },
131	    );
132	
133	    describe('tied ranks', () => {
134	        it('blanks out subsequent tied rows visually, while keeping the rank in the accessible text', () => {
135	            render(
136	                <Wrapper>
137	                    <RecordsTable
138	                        table={TableNameSchema.enum.points}
139	                        year={2024}
140	                        records={[
141	                            createMockPlayerRecordData({ id: 1, rankPoints: 1 }),
142	                            createMockPlayerRecordData({ id: 2, rankPoints: 2 }),
143	                            createMockPlayerRecordData({ id: 3, rankPoints: 2 }),
144	                            createMockPlayerRecordData({ id: 4, rankPoints: 4 }),
145	                        ]}
146	                    />
147	                </Wrapper>,
148	            );
149	
150	            // Row 3 has no visible "2" (it's implied by row 2 above it), but its
151	            // accessible text still contains "2" so screen reader users get the
152	            // value on every row, not just the first row of the tie.
153	            expect(getRankColumnValues()).toEqual(['1', '2', '2', '4']);
154	
155	            const tiedRowCell = getRankCell(2);
156	            expect(getRankCellVisibleText(tiedRowCell)).toBe('');
157	            expect(tiedRowCell).toHaveTextContent('2');
158	        });
159	
160	        it('applies the same treatment to a three-way tie', () => {
161	            render(
162	                <Wrapper>
163	                    <RecordsTable
164	                        table={TableNameSchema.enum.points}
165	                        year={2024}
166	                        records={[
167	                            createMockPlayerRecordData({ id: 1, rankPoints: 1 }),
168	                            createMockPlayerRecordData({ id: 2, rankPoints: 1 }),
169	                            createMockPlayerRecordData({ id: 3, rankPoints: 1 }),
170	                        ]}
171	                    />
172	                </Wrapper>,
173	            );
174	
175	            expect(getRankColumnValues()).toEqual(['1', '1', '1']);
176	
177	            expect(getRankCellVisibleText(getRankCell(0))).toBe('1');
178	            expect(getRankCellVisibleText(getRankCell(1))).toBe('');
179	            expect(getRankCellVisibleText(getRankCell(2))).toBe('');
180	        });
181	    });
182	
183	    describe('missing ranks', () => {
184	        it('renders "-" independently for each consecutive missing rank, without treating them as a tie', () => {
185	            render(
186	                <Wrapper>
187	                    <RecordsTable
188	                        table={TableNameSchema.enum.points}
189	                        year={2024}
190	                        records={[
191	                            createMockPlayerRecordData({ id: 1, rankPoints: undefined }),
192	                            createMockPlayerRecordData({ id: 2, rankPoints: null }),
193	                            createMockPlayerRecordData({ id: 3, rankPoints: 1 }),
194	                        ]}
195	                    />
196	                </Wrapper>,
197	            );
198	
199	            expect(getRankColumnValues()).toEqual(['-', '-', '1']);
200	
201	            // Every "-" is fully visible content, not a blanked continuation
202	            // row with an accessible-only value hiding behind it.
203	            expect(getRankCellVisibleText(getRankCell(0))).toBe('-');
204	            expect(getRankCellVisibleText(getRankCell(1))).toBe('-');
205	            expect(getRankCellVisibleText(getRankCell(2))).toBe('1');
206	        });
207	
208	        it('does not treat a real rank as tied with a preceding missing rank', () => {
209	            render(
210	                <Wrapper>
211	                    <RecordsTable
212	                        table={TableNameSchema.enum.points}
213	                        year={2024}
214	                        records={[
215	                            createMockPlayerRecordData({ id: 1, rankPoints: undefined }),
216	                            createMockPlayerRecordData({ id: 2, rankPoints: 2 }),
217	                            createMockPlayerRecordData({ id: 3, rankPoints: 2 }),
218	                        ]}
219	                    />
220	                </Wrapper>,
221	            );
222	
223	            expect(getRankColumnValues()).toEqual(['-', '2', '2']);
224	            expect(getRankCellVisibleText(getRankCell(1))).toBe('2');
225	            expect(getRankCellVisibleText(getRankCell(2))).toBe('');
226	        });
227	    });
228	
229	    describe('show more / show less', () => {
230	        const untiedRecords = Array.from(
231	            { length: config.recordsTableVisibleRows + 5 },
232	            (_, index) => createMockPlayerRecordData({ id: index + 1, rankPoints: index + 1 }),
233	        );
234	
235	        it('renders only the configured number of rows, with a "show more" toggle', () => {
236	            render(
237	                <Wrapper>
238	                    <RecordsTable
239	                        table={TableNameSchema.enum.points}
240	                        year={2024}
241	                        records={untiedRecords}
242	                    />
243	                </Wrapper>,
244	            );
245	
246	            expect(extractMockProps<PlayerLinkProps>('PlayerLink')).toHaveLength(
247	                config.recordsTableVisibleRows,
248	            );
249	            expect(screen.getByRole('button', { name: 'Show 5 more' })).toBeInTheDocument();
250	        });
251	
252	        it('reveals the remaining rows when the toggle is clicked, then hides them again', async () => {
253	            const user = userEvent.setup();
254	            render(
255	                <Wrapper>
256	                    <RecordsTable
257	                        table={TableNameSchema.enum.points}
258	                        year={2024}
259	                        records={untiedRecords}
260	                    />
261	                </Wrapper>,
262	            );
263	
264	            await user.click(screen.getByRole('button', { name: 'Show 5 more' }));
265	
266	            expect(extractMockProps<PlayerLinkProps>('PlayerLink')).toHaveLength(untiedRecords.length);
267	            const showLess = screen.getByRole('button', { name: 'Show less' });
268	
269	            await user.click(showLess);
270	
271	            expect(extractMockProps<PlayerLinkProps>('PlayerLink')).toHaveLength(
272	                config.recordsTableVisibleRows,
273	            );
274	        });
275	
276	        it('does not render a toggle when all rows already fit', () => {
277	            render(
278	                <Wrapper>
279	                    <RecordsTable
280	                        table={TableNameSchema.enum.points}
281	                        year={2024}
282	                        records={defaultPlayerRecordDataList}
283	                    />
284	                </Wrapper>,
285	            );
286	
287	            expect(screen.queryByRole('button', { name: /show/i })).not.toBeInTheDocument();
288	        });
289	
290	        it('does not split a tie straddling the cutoff', () => {
291	            const tiedAcrossCutoff = untiedRecords.map((record, index) =>
292	                index === config.recordsTableVisibleRows ?
293	                    { ...record, rankPoints: config.recordsTableVisibleRows } :
294	                    record,
295	            );
296	
297	            render(
298	                <Wrapper>
299	                    <RecordsTable
300	                        table={TableNameSchema.enum.points}
301	                        year={2024}
