1	export interface GroupDisplay {
2	    visible: boolean;
3	}
4	
5	/**
6	 * Marks which rows in a pre-grouped list start a new group ("visible") versus
7	 * continue the previous row's group. `groupKey` should return a value unique
8	 * to rows that must never be treated as grouped together (e.g. missing data).
9	 */
10	export const groupDisplays = <T>(rows: T[], groupKey: (row: T) => unknown): GroupDisplay[] => {
11	    const displays: GroupDisplay[] = [];
12	    let prevKey: unknown;
13	
14	    rows.forEach((row, index) => {
15	        const key = groupKey(row);
16	        displays.push({ visible: index === 0 || key !== prevKey });
17	        prevKey = key;
18	    });
19	
20	    return displays;
21	};
22	
23	// Extends the initial page of rows forward past any group straddling the
24	// cutoff, so a group of related rows is never split across a "show more" toggle.
25	export const visibleRowCount = (groups: GroupDisplay[], initial: number): number => {
26	    let count = Math.min(initial, groups.length);
27	
28	    while (count < groups.length && !groups[count].visible) {
29	        count++;
30	    }
31	
32	    return count;
33	};
